t,w,b = map(int, input().split())

def gcd(a,b):
    if b == 0:
        return a
    return gcd(b,a%b)

def lcm(a,b):
    return a*b//gcd(a,b)

def sum(a,b,c):
    if a == 1:
        return (b//c)
    if b == 1:
        return (a//c)
    return (a//c)+(b//c)


def solve(t,w,b):
    g = gcd(w,b)
    l = lcm(w,b)
    if l > t:
        print(0)
    else:
        ans = (t//l) - sum(t,w,l) - sum(t,b,l) + sum(t,l,l)
        g = gcd(ans,t)
        print(ans//g,t//g,sep='/')

solve(t,w,b)
